import React, { useEffect, useRef, useState } from "react";

export default function MessageForm({ onSend, draftInjection }) {
  const [text, setText] = useState("");
  const [files, setFiles] = useState([]);
  const [sending, setSending] = useState(false);
  const fileInputRef = useRef(null);
  const inputRef = useRef(null);

  useEffect(() => {
    if (!draftInjection?.text) return;
    setText(draftInjection.text);
    if (inputRef.current) {
      inputRef.current.focus();
      inputRef.current.setSelectionRange(draftInjection.text.length, draftInjection.text.length);
    }
  }, [draftInjection]);

  const submit = (event) => {
    event.preventDefault();
    if (!text.trim() && !files.length) return;

    setSending(true);
    Promise.resolve(onSend({ content: text, files }))
      .then(() => {
        setText("");
        setFiles([]);
        if (fileInputRef.current) fileInputRef.current.value = "";
      })
      .finally(() => setSending(false));
  };

  const onDrop = (event) => {
    event.preventDefault();
    const dropped = Array.from(event.dataTransfer.files || []).slice(0, 5);
    if (!dropped.length) return;
    setFiles(dropped);
  };

  return (
    <form className="message-form" onSubmit={submit}>
      <div className="message-input-wrap" onDrop={onDrop} onDragOver={(event) => event.preventDefault()}>
        <input
          ref={inputRef}
          type="text"
          placeholder="Type a message here..."
          value={text}
          onChange={(event) => setText(event.target.value)}
          maxLength={1000}
        />
        <input
          ref={fileInputRef}
          type="file"
          multiple
          className="file-input-hidden"
          onChange={(event) => setFiles(Array.from(event.target.files || []).slice(0, 5))}
        />
        {files.length ? <small className="attach-hint">{files.length} file(s) ready</small> : null}
      </div>
      <button className="primary-btn send-btn" type="submit" disabled={sending} aria-label="Send message">
        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
          <path d="m22 2-7 20-4-9-9-4z" />
          <path d="M22 2 11 13" />
        </svg>
      </button>
    </form>
  );
}
